# tests/runbooks/test_runbook_coverage.py
import os, yaml
from pathlib import Path

RUNBOOKS_DIR = Path("runbooks/")
CONTACTS_FILE = Path("config/escalation-contacts.yaml")

def test_all_trigger_conditions_have_runbooks():
    contacts = yaml.safe_load(CONTACTS_FILE.read_text())
    runbook_slugs = {p.stem for p in RUNBOOKS_DIR.glob("*.md")}
    missing = []
    for tier in contacts["tiers"]:
        for condition in tier.get("trigger_conditions", []):
            # Convention: trigger_condition maps to runbook slug
            expected = condition.replace("_", "-")
            if expected not in runbook_slugs:
                missing.append((tier["tier"], condition, expected))
    assert not missing, f"Missing runbooks for trigger conditions: {missing}"

def test_escalation_contacts_reachable():
    contacts = yaml.safe_load(CONTACTS_FILE.read_text())
    for tier in contacts["tiers"]:
        assert tier.get("sla_minutes") is not None, f"Tier {tier['tier']} missing SLA"
        assert tier.get("contact_methods"), f"Tier {tier['tier']} has no contact methods"
